using System;
using System.Collections.Generic;
using System.Xml;

public class ConfigParser
{
    public Dictionary<string, string> ParseConfig(string filePath)
    {
        XmlDocument xmlDoc = new XmlDocument();
        try
        {
            xmlDoc.Load(filePath);
        }
        catch (XmlException ex) when (ex.HResult == 0x80040001)
        {
            // Ignore DTD validation errors
            return null;
        }

        Dictionary<string, string> configSettings = new Dictionary<string, string>();

        foreach (XmlNode node in xmlDoc.DocumentElement.ChildNodes)
        {
            if (node.NodeType == XmlNodeType.Element)
            {
                configSettings.Add(node.Name, node.InnerText);
            }
        }

        return configSettings;
    }
}